#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-07-11

set -euo pipefail

# prune-playgrounds.sh — archive merged PR-playground dirs off main.
#
# The PR Playground gate (ci.yml) mandates a committed docs/<branch-slug>/*.html
# per PR. Those dirs merge to main and accumulate forever. This moves dirs whose
# branch is already gone from origin onto the orphan `playgrounds-archive`
# branch, then removes them from main via a PR (never a direct push to main).
#
# Usage:
#   scripts/prune-playgrounds.sh scan     # report prunable dirs (no mutation)
#   scripts/prune-playgrounds.sh apply    # archive + open a removal PR
#
# Env:
#   OLDER_THAN_DAYS   only prune dirs whose last commit is older than N days (default 30)
#
# Invariants:
#   - Only ever touches docs/<type>--<slug>/ dirs (branch-slug naming).
#   - Hard-excludes the KEEP set below regardless of anything else.
#   - A dir is prunable only if NO branch matching its slug exists on origin
#     (i.e. the PR merged and the branch was deleted).

MODE="${1:-scan}"
OLDER_THAN_DAYS="${OLDER_THAN_DAYS:-30}"
ARCHIVE_BRANCH="playgrounds-archive"

# Real docs dirs that happen to sit under docs/ — never prune these.
KEEP_SET="audits site playgrounds templates stubs readme-hero-banner codescan-zizmor-remediation release-window-786 feat--activation-audit"

is_kept() {
  local name="$1" k
  for k in ${KEEP_SET}; do
    [ "${name}" = "${k}" ] && return 0
  done
  return 1
}

# origin branch slugs (branch name with / → -- to match the docs dir convention).
# A missing/unreachable remote yields an empty set → nothing is treated as merged,
# so the scan is conservative (prunes nothing) rather than wrong.
origin_slugs() {
  # silent: best-effort — unreachable remote ⇒ empty set ⇒ conservative (prunes nothing)
  git ls-remote --heads origin 2>/dev/null \
    | sed -E 's#^.*refs/heads/##; s#/#--#g' \
    | sort -u
}

collect_prunable() {
  local cutoff live d name last
  cutoff=$(( $(date +%s) - OLDER_THAN_DAYS * 86400 ))
  live="$(origin_slugs)"
  for d in docs/*--*/; do
    [ -d "${d}" ] || continue
    name="$(basename "${d}")"
    if is_kept "${name}"; then continue; fi
    # skip if a matching branch still exists on origin (PR not merged/deleted yet).
    # here-string (not a pipe) so grep -q cannot SIGPIPE the producer under pipefail.
    if grep -qxF "${name}" <<<"${live}"; then continue; fi
    # age gate: newest commit touching the dir must be older than the cutoff.
    # A dir with no history (brand new, unstaged) reports 0 → treated as old.
    # silent: best-effort — no history for a fresh dir is expected, default 0
    last="$(git log -1 --format=%ct -- "${d}" 2>/dev/null || echo 0)"
    if [ "${last}" -gt "${cutoff}" ]; then continue; fi
    printf '%s\n' "${name}"
  done
}

count_lines() {
  # 0 for empty input, else the number of non-empty lines (no grep → no pipefail trap).
  local s="$1"
  [ -z "${s}" ] && { echo 0; return; }
  printf '%s\n' "${s}" | awk 'NF{n++} END{print n+0}'
}

main() {
  local list count
  list="$(collect_prunable)"
  count="$(count_lines "${list}")"

  echo "Prunable playground dirs (branch gone from origin, older than ${OLDER_THAN_DAYS}d): ${count}"
  [ -n "${list}" ] && printf '%s\n' "${list}" | sed 's/^/  /'

  if [ -n "${GITHUB_OUTPUT:-}" ]; then
    echo "count=${count}" >> "${GITHUB_OUTPUT}"
  fi

  [ "${MODE}" = "scan" ] && return 0
  [ "${count}" = "0" ] && { echo "Nothing to prune."; return 0; }

  echo "Applying: archiving ${count} dir(s) to ${ARCHIVE_BRANCH}, then opening a removal PR."

  git config user.name  "github-actions[bot]"
  git config user.email "github-actions[bot]@users.noreply.github.com"

  # 1. append the dirs to the archive branch via an isolated worktree.
  git fetch origin "${ARCHIVE_BRANCH}" --quiet
  local wt name
  wt="$(mktemp -d)"
  git worktree add --quiet "${wt}" "origin/${ARCHIVE_BRANCH}"
  for name in ${list}; do
    mkdir -p "${wt}/docs"
    cp -R "docs/${name}" "${wt}/docs/${name}"
  done
  git -C "${wt}" add docs
  if git -C "${wt}" diff --cached --quiet; then
    echo "(archive branch already has these dirs — no new archive commit)"
  else
    git -C "${wt}" commit -q -m "archive: +${count} merged playground dir(s)"
    git -C "${wt}" push -q origin "HEAD:${ARCHIVE_BRANCH}"
  fi
  git worktree remove --force "${wt}"

  # 2. remove from main on a dated branch → PR (never push straight to main).
  local branch
  branch="chore/prune-playgrounds-$(date +%Y%m%d%H%M%S)"
  git switch -c "${branch}"
  for name in ${list}; do
    git rm -rq "docs/${name}"
  done
  git commit -q -m "chore: prune ${count} archived playground dir(s) from main

Moved to ${ARCHIVE_BRANCH} by scripts/prune-playgrounds.sh. Branches merged +
deleted from origin; content preserved on the archive branch and in history."
  git push -q -u origin "${branch}"
  echo "Pushed ${branch}. Open a PR to land the removal."
}

main
